import React, { useState, useEffect } from 'react';

function App() {
  const [balance, setBalance] = useState(10000);
  const [isBotActive, setIsBotActive] = useState(false);
  const [positions, setPositions] = useState([]);

  useEffect(() => {
    const interval = setInterval(() => {
      setBalance(prev => prev + (Math.random() - 0.5) * 50);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const toggleBot = () => setIsBotActive(!isBotActive);

  return (
    <div className="min-h-screen p-6">
      {/* Header */}
      <div className="glass p-8 rounded-3xl text-center mb-8">
        <h1 className="text-5xl font-black uppercase tracking-widest bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent mb-4">
          ALGO TRADER PRO
        </h1>
        <p className="text-xl text-blue-300 font-medium">Next-Gen Automated Trading</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Control Panel */}
        <div className="glass p-6 rounded-2xl">
          <h3 className="text-2xl font-neuromorph mb-6 text-center">CONTROL PANEL</h3>
          <div className="space-y-4">
            <button 
              onClick={toggleBot}
              className={`w-full py-4 rounded-2xl font-neuromorph text-lg uppercase tracking-wider transition-all duration-300 ${isBotActive ? 'bg-green-500/30 border-green-500/50 hover:bg-green-500/50' : 'btn-primary hover:scale-105'}`}
            >
              {isBotActive ? '🟢 BOT ACTIVE' : '🔴 START BOT'}
            </button>
            <div className="text-center p-4 bg-gradient-to-r from-yellow-500/20 to-orange-500/20 rounded-xl border border-yellow-500/30">
              <p className="font-digital text-sm opacity-80">License: TRADING-PRO-2024-001</p>
              <p className="font-digital text-xs opacity-60 mt-1">Device Bound ✓</p>
            </div>
          </div>
        </div>

        {/* Balance */}
        <div className="glass p-6 rounded-2xl text-center">
          <h3 className="text-xl font-neuromorph mb-4">ACCOUNT BALANCE</h3>
          <div className="text-4xl font-black">
            ${balance.toLocaleString()}
          </div>
          <p className="text-green-400 font-digital mt-2">+2.4% Today</p>
        </div>

        {/* Strategy Selector */}
        <div className="glass p-6 rounded-2xl">
          <h3 className="text-xl font-neuromorph mb-4 text-center">ACTIVE STRATEGY</h3>
          <div className="bg-gradient-to-r from-emerald-500/20 to-teal-500/20 p-4 rounded-xl border border-emerald-500/30">
            <p className="font-neuromorph text-lg text-center">AI/ML Predictor</p>
            <p className="text-xs text-emerald-300 text-center mt-1">95% Win Rate</p>
          </div>
        </div>
      </div>

      {/* Positions */}
      <div className="glass mt-8 p-6 rounded-3xl">
        <h3 className="text-2xl font-neuromorph mb-6 text-center">LIVE POSITIONS</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {positions.map((pos, i) => (
            <div key={i} className="p-4 bg-white/5 rounded-xl border border-white/10">
              <p className="font-digital text-sm opacity-70">NIFTY</p>
              <p className="text-lg font-bold text-green-400">+₹2,450</p>
              <p className="text-xs text-gray-400">LONG • 2h 15m</p>
            </div>
          ))}
          <div className="p-4 bg-gradient-to-r from-blue-500/20 to-purple-500/20 rounded-xl border border-blue-500/30 text-center">
            <p className="font-neuromorph text-lg">+ NEW TRADE</p>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="text-center mt-12 opacity-50 text-sm font-digital">
        Supports: Dhan • AngelOne • MT4 • MT5 • Crypto
      </div>
    </div>
  );
}

export default App;
